SELECT [Sales Line].[Document No_], [Sales Line].Type, [Sales Line].[model item no_], [Sales Line].[variable code 01], [Sales Line].[variable code 02], Item.[season code], Item.[trademark code], [NavisionEan-step0].[Cross-Reference No_], Val([item.net weight]) AS pesonetto, Val([item.gross weight]) AS pesolordo, Val([quantity]) AS qty
FROM ([Sales Line] LEFT JOIN [NavisionEan-step0] ON [Sales Line].No_ = [NavisionEan-step0].[Item No_]) INNER JOIN Item ON [Sales Line].No_ = Item.No_
WHERE ((([Sales Line].[Document No_])="OV-21/07845" Or ([Sales Line].[Document No_])="OV-21/07846" Or ([Sales Line].[Document No_])="OV-21/07847" Or ([Sales Line].[Document No_])="OV-21/07848" Or ([Sales Line].[Document No_])="OV-21/07849" Or ([Sales Line].[Document No_])="OV-21/07853" Or ([Sales Line].[Document No_])="OV-21/07854" Or ([Sales Line].[Document No_])="OV-21/07855" Or ([Sales Line].[Document No_])="OV-21/07856" Or ([Sales Line].[Document No_])="OV-21/07857" Or ([Sales Line].[Document No_])="OV-21/07858" Or ([Sales Line].[Document No_])="OV-21/07859" Or ([Sales Line].[Document No_])="OV-21/07861" Or ([Sales Line].[Document No_])="OV-21/07862" Or ([Sales Line].[Document No_])="OV-21/07863" Or ([Sales Line].[Document No_])="OV-21/07865" Or ([Sales Line].[Document No_])="OV-21/07899") AND (([Sales Line].Type)=2));

